pub fn remove(self) -> StreamId {
    // The stream must have been unlinked before this point
    debug_assert!(!self.store.ids.contains_key(&self.key.stream_id));

    // Remove the stream state
    let stream = self.store.slab.remove(self.key.index.0 as usize);
    assert_eq!(stream.id, self.key.stream_id);
    stream.id
}

pub(crate) fn insert(&mut self, name: HeaderName) {
    if !self.num_entries.contains_key(&name) {
        let idx = 0;
        self.num_entries.insert(name.clone(), 1);
        self.entry_order.push((name, idx));
    }
    // Replacing an already existing element does not
    // change ordering, so we only care if its the first
    // header name encountered
}

pub(crate) fn disable_keep_alive(&mut self) {
    self.conn.disable_keep_alive();

    // If keep alive has been disabled and no read or write has been seen on
    // the connection yet, we must be in a state where the server is being asked to
    // shut down before any data has been seen on the connection
    if self.conn.is_write_closed() || self.conn.has_initial_read_write_state() {
        self.close();
    }
}

fn drop(&mut self) {
    if self.open {
        // starts a rollback operation

        // what this does depends on the database but generally this means we queue a rollback
        // operation that will happen on the next asynchronous invocation of the underlying
        // connection (including if the connection is returned to a pool)

        DB::TransactionManager::start_rollback(&mut self.connection);
    }
}

async fn close(mut self) -> Result<(), Error> {
    // The normal, graceful termination procedure is that the frontend sends a Terminate
    // message and immediately closes the connection.

    // On receipt of this message, the backend closes the
    // connection and terminates.
    self.inner.stream.send(Terminate).await?;
    self.inner.stream.shutdown().await?;

    Ok(())
}

fn main() {
    // connect to DX CLI and patch the WASM binary whenever we receive a message
    connect_to_hot_patch_messages();

    // wrapping App here in a closure so we can hot-reload it, because we only do that
    // for reactive views right now. changing anything will re-run App and update the view
    mount_to_body(|| App);
}

fn finalize(&mut self) {
    self.push_digit(self.predigit);
    for _ in 0..self.nines {
        self.push_digit(9);
    }
    self.nines = 0;
    // The spigot algorithm produces digits starting with 3; strip it.
    if self.result.starts_with('3') {
        self.result.remove(0);
    }
}

pub(crate) async fn recv(&mut self) {
    // If the shutdown signal has already been received, then return
    // immediately.
    if self.is_shutdown {
        return;
    }

    // Cannot receive a "lag error" as only one value is ever sent.
    let _ = self.notify.recv().await;

    // Remember that the signal has been received.
    self.is_shutdown = true;
}

pub fn new(socket: TcpStream) -> Connection {
    Connection {
        stream: BufWriter::new(socket),
        // Default to a 4KB read buffer. For the use case of mini redis,
        // this is fine. However, real applications will want to tune this
        // value to their specific use case. There is a high likelihood that
        // a larger read buffer will work better.
        buffer: BytesMut::with_capacity(4 * 1024),
    }
}

pub async fn subscribe(mut self, channels: Vec<String>) -> crate::Result<Subscriber> {
    // Issue the subscribe command to the server and wait for confirmation.
    // The client will then have been transitioned into the "subscriber"
    // state and may only issue pub/sub commands from that point on.
    self.subscribe_cmd(&channels).await?;

    // Return the `Subscriber` type
    Ok(Subscriber {
        client: self,
        subscribed_channels: channels,
    })
}

pub(crate) unsafe fn add_entry(&mut self, hdl: EntryHandle) {
    // Safety: the associated entry must be valid.
    let deadline = hdl.deadline();
    let slot = slot_for(deadline, self.level);

    self.slot[slot].push_front(hdl);

    self.occupied |= occupied_bit(slot);
}

fn drop(&mut self) {
    let mut waiters = self.scheduled_io.waiters.lock();

    // Safety: `waiter` is only ever stored in `waiters`
    unsafe {
        waiters
            .list
            .remove(NonNull::new_unchecked(self.waiter.get()))
    };
}

pub(super) fn release(&self, synced: &mut Synced) {
    let pending = std::mem::take(&mut synced.pending_release);

    for io in pending {
        // safety: the registration is part of our list
        unsafe { self.remove(synced, &io) }
    }

    self.num_pending_release.store(0, Release);
}

fn bench_contention(c: &mut Criterion) {
    let mut group = c.benchmark_group("contention");
    contention_bounded(&mut group);
    contention_bounded_recv_many(&mut group);
