pub fn abort_matching(&mut self, mut predicate: impl FnMut(&K) -> bool) {
    // Note: this method iterates over the tasks and keys *without* removing
    // any entries, so that the keys from aborted tasks can still be
    // returned when calling `join_next` in the future.
    for (key, task) in &self.tasks_by_key {
        if predicate(key) {
            task.abort();
        }
    }
}

unsafe fn with_inner<F, R>(&self, f: F) -> R
    where
        F: FnOnce(&mut Option<Rc<T>>) -> R,
    {
        // safety: This type is not Sync, so concurrent calls of this method
        // cannot happen. Furthermore, the caller guarantees that the method is
        // not called recursively. Finally, this is the only place that can
        // create mutable references to the inner Rc. This ensures that any
        // mutable references created here are exclusive.
        self.inner.with_mut(|ptr| f(unsafe { &mut *ptr }))
    }

pub(crate) fn defer(&self, waker: &Waker) {
    let mut deferred = self.deferred.borrow_mut();

    // If the same task adds itself a bunch of times, then only add it once.
    if let Some(last) = deferred.last() {
        if last.will_wake(waker) {
            return;
        }
    }

    deferred.push(waker.clone());
}

fn drop(&mut self) {
    let context = self.context.expect_current_thread();

    if let Some(core) = context.core.borrow_mut().take() {
        // Replace old scheduler back into the state to allow
        // other threads to pick it up and drive it.
        self.scheduler.core.set(core);

        // Wake up other possible threads that could steal the driver.
        self.scheduler.notify.notify_one();
    }
}

pub(crate) fn push(&self, value: T) {
    // First, claim a slot for the value. `Acquire` is used here to
    // synchronize with the `fetch_add` in `reclaim_blocks`.
    let slot_index = self.tail_position.fetch_add(1, Acquire);

    // Load the current block and write the value
    let block = self.find_block(slot_index);

    unsafe {
        // Write the value to the block
        block.as_ref().write(slot_index, value);
    }
}

fn next_expiration(&self) -> Option<Expiration> {
    // Check all levels
    for level in 0..NUM_LEVELS {
        if let Some(expiration) = self.levels[level].next_expiration(self.elapsed) {
            // There cannot be any expirations at a higher level that happen
            // before this one.
            debug_assert!(self.no_expirations_before(level + 1, expiration.deadline));

            return Some(expiration);
        }
    }

    None
}

pub(crate) fn cancel(&self) {
    let mut lock = self.entry.state.lock();
    if !lock.cancelled {
        lock.cancelled = true;
        if let Some(cancel_tx) = lock.cancel_tx.take() {
            drop(lock);

            // Safety: we can guarantee that `self` is not in any cancellation queue
            // because the `self.cancelled` was just set to `true`.
            unsafe {
                cancel_tx.send(self.clone());
            }
        }
    }
}
